/**
 * 错误用例测试
 * 这个文件包含各种应该被 ESLint 标记为错误的代码
 * 用于验证 ESLint 规则是否正确工作
 */

/* eslint-disable */
// 注意: 这个文件故意包含错误，用于测试 ESLint 规则

// ========== 语法错误 ==========

// 缺少分号
const missingsemicolon = 'this line is missing a semicolon'

// 使用 var 而不是 const/let
var oldStyleVariable = 'should use const or let';

// 使用双等号而不是三等号
function badComparison(value) {
  if (value == 'test') {
    return true;
  }
  return false;
}

// ========== 样式错误 ==========

// 使用双引号而不是单引号
const wrongQuotes = "should use single quotes";

// 缺少空格
const noSpaces=1+2+3;

// 错误的缩进
function badIndentation() {
console.log('bad indentation');
  if (true) {
console.log('inconsistent indentation');
  }
}

// 多余的空行


const tooManyEmptyLines = 'above';

// 行尾空格
const trailingSpaces = 'this line has trailing spaces';   

// ========== 变量错误 ==========

// 未使用的变量
const unusedVariable = 'this variable is never used';

// 重复声明
let duplicateVar = 1;
let duplicateVar = 2;

// 使用未声明的变量
function useUndeclaredVariable() {
  return undeclaredVariable;
}

// ========== 函数错误 ==========

// 箭头函数不必要的花括号
const unnecessaryBraces = (x) => {
  return x * 2;
};

// 函数参数重新赋值
function reassignParameter(param) {
  param = 'modified';
  return param;
}

// 空函数体
function emptyFunction() {
}

// ========== 对象和数组错误 ==========

// 对象属性引号不一致
const inconsistentQuotes = {
  'quoted': 'value',
  unquoted: 'value'
};

// 数组中多余的逗号
const arrayWithExtraComma = [1, 2, 3,];

// 对象中缺少逗号
const missingComma = {
  first: 'value'
  second: 'value'
};

// ========== ES6 错误 ==========

// 不必要的构造函数
class UnnecessaryConstructor {
  constructor() {
    super();
  }
}

// 重复的类成员
class DuplicateMembers {
  method() {
    return 'first';
  }

  method() {
    return 'duplicate';
  }
}

// 无用的重命名
const { name: name } = { name: 'test' };

// ========== 导入导出错误 ==========

// 导入不存在的模块
import nonExistentModule from './non-existent.js';

// 重复导入
import { something } from './module.js';
import { something } from './module.js';

// 导出可变绑定
export let mutableExport = 'should not export mutable';

// ========== 其他错误 ==========

// 使用 eval
const dangerousEval = eval('1 + 1');

// 使用 with 语句
with (Math) {
  const result = sqrt(16);
}

// 不安全的否定
if (!key in object) {
  console.log('unsafe negation');
}

// 无限循环
while (true) {
  break;
}

// 不可达代码
function unreachableCode() {
  return 'early return';
  console.log('this will never execute');
}

// 空的 catch 块
try {
  riskyOperation();
} catch (error) {
  // 空的 catch 块
}

// 魔法数字
function calculateArea(radius) {
  return 3.14159 * radius * radius;
}

// console.log 在生产环境中
if (process.env.NODE_ENV === 'production') {
  console.log('this should not be in production');
}

// 导出（这些导出会产生错误）
export {
  missingsemicolon,
  oldStyleVariable,
  badComparison,
  wrongQuotes,
  noSpaces,
  badIndentation,
  unnecessaryBraces,
  reassignParameter,
  emptyFunction,
  inconsistentQuotes,
  UnnecessaryConstructor,
  DuplicateMembers,
  dangerousEval,
  calculateArea,
};

/**
 * 警告用例测试
 * 这个文件包含应该被 ESLint 标记为警告的代码
 * 用于验证警告级别的规则是否正确工作
 */

// ========== 未使用变量警告 ==========

// 未使用的变量（应该产生警告）
const unusedString = 'this variable is not used';
const unusedNumber = 42;
const unusedArray = [1, 2, 3];

// 使用下划线的变量不应该产生警告
const _ = 'this is allowed';

// 使用的变量不应该产生警告
const usedVariable = 'this is used';
console.log(usedVariable);

// ========== 行长度警告 ==========

// 超过 120 字符的行（应该产生警告）
const veryLongLineOfCodeThatExceedsTheMaximumLineLengthConfigurationAndShouldTriggerAWarningFromESLintBecauseItIsTooLong = 'long line';

// 正常长度的行
const normalLine = 'this line is within the limit';

// ========== 函数复杂度警告 ==========

// 复杂度较高的函数（可能产生警告）
function complexFunction(a, b, c, d) {
  if (a > 0) {
    if (b > 0) {
      if (c > 0) {
        if (d > 0) {
          return a + b + c + d;
        }
        return a + b + c;
      }
      return a + b;
    }
    return a;
  }
  return 0;
}

// ========== 类相关警告 ==========

// 每个文件多个类（可能产生警告）
class FirstClass {
  constructor(name) {
    this.name = name;
  }

  getName() {
    return this.name;
  }
}

class SecondClass {
  constructor(value) {
    this.value = value;
  }

  getValue() {
    return this.value;
  }
}

// ========== 函数名称警告 ==========

// 匿名函数表达式（可能产生警告）
const anonymousFunction = function (x) {
  return x * 2;
};

// 命名函数表达式（更好的做法）
const namedFunction = function multiply(x) {
  return x * 2;
};

// ========== console 语句警告 ==========

// 在开发环境中，console.log 应该是允许的
if (process.env.NODE_ENV === 'development') {
  console.log('Development mode logging');
  console.warn('Development warning');
  console.error('Development error');
}

// 在生产环境中，console 语句应该产生警告
if (process.env.NODE_ENV === 'production') {
  console.log('This might produce a warning in production');
}

// ========== debugger 语句警告 ==========

// debugger 在生产环境中应该产生警告
if (process.env.NODE_ENV === 'production') {
  debugger; // 这应该产生警告
}

// ========== 注释相关 ==========

// TODO: 这是一个待办事项注释（可能产生警告）
// FIXME: 这是一个修复注释（可能产生警告）
// XXX: 这是一个注意注释（可能产生警告）

// 正常注释不应该产生警告
// 这是一个正常的注释

// ========== 对象属性访问 ==========

const testObject = {
  'kebab-case': 'value',
  normalProperty: 'value',
};

// 使用点号访问可能产生警告的属性
// console.log(testObject.kebab-case); // 这会产生语法错误

// 使用括号访问是正确的
console.log(testObject['kebab-case']);
console.log(testObject.normalProperty);

// ========== 数组方法使用 ==========

const numbers = [1, 2, 3, 4, 5];

// 使用 for...in 遍历数组（可能产生警告）
for (const index in numbers) {
  console.log(numbers[index]);
}

// 更好的做法
for (const number of numbers) {
  console.log(number);
}

// 或者使用数组方法
numbers.forEach((number) => {
  console.log(number);
});

// ========== 正则表达式 ==========

// 可能产生警告的正则表达式使用
const regexWithoutFlags = new RegExp('pattern');

// 更好的做法
const regexWithFlags = /pattern/gi;

// ========== 类型检查 ==========

function checkType(value) {
  // 使用 typeof 检查（正确做法）
  if (typeof value === 'string') {
    return 'is string';
  }

  // 可能产生警告的类型检查
  if (value instanceof String) {
    return 'is String object';
  }

  return 'unknown type';
}

// ========== 导出 ==========
export {
  unusedString, // 这个导出可能产生警告，因为变量本身未使用
  usedVariable,
  veryLongLineOfCodeThatExceedsTheMaximumLineLengthConfigurationAndShouldTriggerAWarningFromESLintBecauseItIsTooLong,
  normalLine,
  complexFunction,
  FirstClass,
  SecondClass,
  anonymousFunction,
  namedFunction,
  testObject,
  numbers,
  regexWithFlags,
  checkType,
};

/**
 * 自定义规则测试
 * 这个文件测试我们配置中的自定义规则和覆盖规则
 * 验证与 airbnb-base 的差异是否按预期工作
 */

// ========== 我们允许但 airbnb 不允许的规则 ==========

// 1. camelcase: 'off' - 我们允许非驼峰命名
const snake_case_variable = 'allowed in our config';
const kebab_case_function = () => 'also allowed';
const SCREAMING_SNAKE_CASE = 'constants are fine';

// 2. class-methods-use-this: 'off' - 我们允许不使用 this 的类方法
class UtilityClass {
  // 这个方法不使用 this，但在我们的配置中是允许的
  static formatDate(date) {
    return date.toISOString();
  }

  // 实例方法不使用 this 也是允许的
  getCurrentTimestamp() {
    return Date.now();
  }
}

// 3. dot-notation: 'off' - 我们允许括号访问属性
const config = {
  'api-url': 'https://api.example.com',
  'max-retries': 3,
};

// 这些访问方式都是允许的
const apiUrl = config['api-url']; // 括号访问
const maxRetries = config['max-retries']; // 括号访问
const normalProp = config.normalProp; // 点访问

// 4. no-else-return: 'off' - 我们允许 else return
function processValue(value) {
  if (value > 0) {
    return 'positive';
  } else {
    return 'non-positive'; // 允许 else return
  }
}

// 5. no-new: 'off' - 我们允许 new 但不赋值
function initializeLibrary() {
  new Date(); // 允许这种用法
  new Promise((resolve) => resolve()); // 也允许
}

// 6. no-new-wrappers: 'off' - 我们允许包装对象
const stringObject = new String('test'); // 允许
const numberObject = new Number(42); // 允许
const booleanObject = new Boolean(true); // 允许

// 7. no-param-reassign: 'off' - 我们允许参数重新赋值
function modifyParameter(param) {
  param = param || 'default'; // 允许修改参数
  return param;
}

function modifyObjectParameter(obj) {
  obj.modified = true; // 允许修改对象属性
  return obj;
}

// 8. no-continue: 'off' - 我们允许 continue 语句
function processArray(items) {
  const results = [];

  for (const item of items) {
    if (!item.isValid) {
      continue; // 允许使用 continue
    }
    results.push(item.process());
  }

  return results;
}

// 9. no-plusplus: 'off' - 我们允许 ++ 和 --
function countUp(max) {
  const results = [];
  for (let i = 0; i < max; i++) { // 允许 i++
    results.push(i);
  }
  return results;
}

// 10. no-restricted-syntax: 'off' - 我们允许 for...in 和 for...of
function demonstrateLoops(obj, arr) {
  // for...in 循环是允许的
  for (const key in obj) {
    if (obj.hasOwnProperty(key)) {
      console.log(key, obj[key]);
    }
  }

  // for...of 循环也是允许的
  for (const item of arr) {
    console.log(item);
  }
}

// 11. no-shadow: 'off' - 我们允许变量遮蔽
const name = 'global';

function shadowExample() {
  const name = 'local'; // 允许遮蔽全局变量
  return name;
}

// 12. no-underscore-dangle: 'off' - 我们允许下划线
const _privateVariable = 'allowed';
const obj = {
  _internalMethod() {
    return 'internal';
  },
  publicMethod() {
    return this._internalMethod();
  },
};

// 13. no-unused-expressions: 'off' - 我们允许未使用的表达式
function allowUnusedExpressions() {
  'use strict'; // 允许字符串表达式

  const result = someCondition && someFunction(); // 允许短路表达式

  someCondition ? doSomething() : doSomethingElse(); // 允许三元表达式
}

// ========== 我们的自定义配置 ==========

// 14. 我们的 no-unused-vars 配置允许 _ 变量
function withUnusedUnderscore() {
  const _ = 'this is allowed'; // 不会产生警告
  const unused = 'this will produce warning'; // 会产生警告

  return 'done';
}

// 15. 我们的 max-len 配置是 120 字符，并且忽略注释和字符串
const longString = 'This is a very long string that exceeds the normal line length but should be allowed because we ignore strings in our max-len rule configuration';

// 这个注释非常长，但应该被忽略：This is a very long comment that exceeds the normal line length but should be allowed because we ignore comments in our max-len rule configuration

// 16. 我们的 comma-dangle 配置
const multilineObject = {
  first: 'value',
  second: 'value',
  third: 'value', // 要求尾随逗号
};

const singleLineObject = { first: 'value', second: 'value' }; // 不要求尾随逗号

// 17. 我们的 indent 配置处理装饰器
class DecoratedClass {
  // 这种缩进应该是正确的，即使有装饰器
  @decorator
  decoratedMethod() {
    return 'decorated';
  }
}

// 18. 我们的 spaced-comment 配置
// 这是正确的注释格式
/* 这也是正确的块注释格式 */

//这种注释格式可能会产生警告（缺少空格）
/*这种块注释格式也可能会产生警告*/

// ========== Import/Export 自定义规则 ==========

// 我们的配置中这些 import 规则是关闭的或修改的：
// - import/no-unresolved: 'off'
// - import/no-extraneous-dependencies: 'off'
// - import/prefer-default-export: 'off'
// - import/first: 'off'
// - import/extensions: 'off'

// 因此这些应该是允许的：
import nonExistentModule from './non-existent-module.js'; // 通常会报错，但我们关闭了
import devDependency from 'some-dev-dependency'; // 通常会报错，但我们关闭了

// 单个导出不要求默认导出
export const singleExport = 'allowed';

// 导入不必须在顶部
const someCode = 'before import';
import lateImport from './some-module.js'; // 允许

// ========== 测试我们的环境配置 ==========

// 我们配置了多种环境，这些全局变量应该是可用的：

// Browser 环境
if (typeof window !== 'undefined') {
  console.log(window.location.href);
  document.getElementById('test');
}

// Node.js 环境
if (typeof process !== 'undefined') {
  console.log(process.env.NODE_ENV);
  console.log(__dirname, __filename);
}

// 测试环境
if (typeof describe !== 'undefined') {
  describe('test suite', () => {
    it('should work', () => {
      expect(true).toBe(true);
    });
  });
}

// ========== 导出 ==========
export {
  snake_case_variable,
  kebab_case_function,
  SCREAMING_SNAKE_CASE,
  UtilityClass,
  apiUrl,
  maxRetries,
  processValue,
  initializeLibrary,
  stringObject,
  numberObject,
  booleanObject,
  modifyParameter,
  modifyObjectParameter,
  processArray,
  countUp,
  demonstrateLoops,
  shadowExample,
  obj,
  allowUnusedExpressions,
  withUnusedUnderscore,
  longString,
  multilineObject,
  singleLineObject,
  DecoratedClass,
  singleExport,
  someCode,
};
